import streamlit as st

from src.screens.home_screen import home_screen
from src.screens.student_screen import student_screen
from src.screens.teacher_screen import teacher_screen
from src.components.dialog_auto_enroll import auto_enroll_dialog


def main():
    st.set_page_config(
        page_title='IntelliAttend AI - Smart Attendance Zero Effort',
        page_icon='data:image/jpeg;base64,'
    )
    if 'login_type' not in st.session_state:
        st.session_state['login_type'] = None

    # check join code first
    join_code = st.query_params.get('join-code')
    if join_code:
        st.session_state['pending_join_code'] = join_code  # 👈 save it
        if st.session_state.login_type != 'student':
            st.session_state.login_type = 'student'
            st.rerun()

    match st.session_state['login_type']:
        case 'teacher':
            teacher_screen()
        case 'student':
            student_screen()
        case None:
            home_screen()

    # after login, auto enroll
    if (st.session_state.get('is_logged_in') and
        st.session_state.get('user_role') == 'student' and
        'pending_join_code' in st.session_state):
        code = st.session_state.pop('pending_join_code')
        auto_enroll_dialog(code)  # 👈 opens popup after face login

main()